import React, { useEffect, useState } from "react";

const TravelHistory = ({ employee }) => {
  const [travelData, setTravelData] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/travel-expenses?empId=${empId}`
      );

      const data = await response.json();
      console.log("TRAVEL DATA:", data);

      setTravelData(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
      setTravelData([]);
    }
  };

  const filtered = travelData.filter((t) => {
    const d = new Date(t.travel_date);
    const f = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;

    if (f && d < f) return false;
    if (to && d > to) return false;

    return true;
  });

  return (
    <div style={page}>
      {/* BACK + TITLE */}
      <div style={headerRow}>
        <button onClick={() => window.history.back()} style={backBtn}>←</button>
        <h2 style={title}>Travel Expense History</h2>
      </div>

      {/* EMP INFO */}
      <p style={empInfo}>
        Employee: {employee.empName || employee.name} •{" "}
        {employee.empId || employee.empld}
      </p>

      {/* FILTER BAR */}
      <div style={filterBox}>
        <div>
          <label>From Date</label><br />
          <input type="date" value={fromDate} onChange={(e)=>setFrom(e.target.value)} style={dateInput} />
        </div>

        <div>
          <label>To Date</label><br />
          <input type="date" value={toDate} onChange={(e)=>setTo(e.target.value)} style={dateInput} />
        </div>

        <button onClick={fetchData} style={refreshBtn}>Reset</button>
      </div>

      {/* TABLE */}
      <table style={table}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>From</th>
            <th>To</th>
            <th>Amount</th>
          </tr>
        </thead>

        <tbody>
          {filtered.length > 0 ? (
            filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.travel_date}</td>
                <td>{t.purpose}</td>
                <td>{t.location_from}</td>
                <td>{t.location_to}</td>
                <td>₹{t.amount}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" style={noData}>No records found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default TravelHistory;

/* 🔥 INLINE UI STYLES 🔥 */

const page = { padding: "20px", background: "#F5FFF7", minHeight: "100vh" };
const headerRow = { display:"flex", alignItems:"center", gap:"10px" };
const backBtn = { background:"white", border:"1px solid #0F9D58", padding:"6px 12px",
  borderRadius:"6px", cursor:"pointer", color:"#0F9D58", fontSize:"18px" };
const title = { color:"#0F9D58", fontSize:"22px", fontWeight:"600" };
const empInfo = { marginTop:"-5px", color:"#333" };

const filterBox = {
  marginTop:"15px",
  display:"flex",
  gap:"20px",
  background:"#E8F6ED",
  padding:"12px",
  borderRadius:"10px"
};

const dateInput = {
  padding:"6px 10px",
  border:"1px solid #CCC",
  borderRadius:"6px"
};

const refreshBtn = {
  background:"#0F9D58",
  color:"white",
  border:"none",
  padding:"8px 14px",
  borderRadius:"6px",
  cursor:"pointer",
  marginTop:"20px"
};

const table = {
  width:"100%",
  marginTop:"20px",
  background:"white",
  borderCollapse:"collapse",
  boxShadow:"0 2px 8px rgba(0,0,0,0.1)"
};

const noData = { textAlign:"center", padding:"20px", color:"#777" };
